// ── パス検証：許可リスト以外は全拒否 ──────────────────
const ALLOWED_PATHS = [
  '_shared/workflow_state.json',
  '_shared/research_briefing.json',
  '_shared/research_output.json',
  '_shared/writing_brief.json',
  '_shared/post_drafts.json',
  '_shared/approved_posts.json',
  '_shared/post_log.json',
  '_shared/daily_metrics.json',
  '_shared/analysis_report.json',
  '_shared/monitoring_alerts.json'
];

const body = $input.first().json.body || $input.first().json;
const filePath = (body.file_path || '').trim();

// パストラバーサル・不正パスを拒否
if (
  !filePath ||
  filePath.includes('..') ||
  filePath.includes('//') ||
  filePath.startsWith('/') ||
  filePath.startsWith('.github') ||
  !ALLOWED_PATHS.includes(filePath)
) {
  throw new Error(`不正なfile_path: "${filePath}"`);
}

const content = typeof body.content === 'string'
  ? body.content
  : JSON.stringify(body.content, null, 2);

if (!content || content.length === 0) {
  throw new Error('content が空です');
}

const message = body.message || `自動更新: ${filePath} at ${new Date().toISOString()}`;

return [{ json: { file_path: filePath, content_raw: content, message } }];

const parseNode = $('リクエストを検証・解析').first().json;
const shaNode = $input.first().json;

const encoded = Buffer.from(parseNode.content_raw).toString('base64');

return [{
  json: {
    file_path: parseNode.file_path,
    message: parseNode.message,
    content: encoded,
    sha: shaNode.sha
  }
}];
